#!/usr/bin/env bash

###############################################################################
#
# Monitoring-Grafana Project
#
# File:
#   scripts/lib/env/helpers.sh
#
# Description:
#   Helper functions for environment files.
#
###############################################################################

###############################################################################
# Is comment
###############################################################################

env_is_comment()
{
    [[ "$1" =~ ^[[:space:]]*# ]]
}

###############################################################################
# Is blank line
###############################################################################

env_is_blank()
{
    [[ -z "$1" ]]
}

###############################################################################
# Is variable
###############################################################################

env_is_variable()
{
    [[ "$1" == *=* ]]
}

###############################################################################
# Variable name
###############################################################################

env_variable_name()
{
    printf '%s\n' "${1%%=*}"
}

###############################################################################
# Variable value
###############################################################################

env_variable_value()
{
    printf '%s\n' "${1#*=}"
}